export default function hoverConfig(e) {
    let timeOut
    let ifTimeOut
    if(e.type === 'mouseenter'){
        timeOut = setTimeout(() => {
            console.log(e.target.innerText);
        }, 1000)
        console.log(timeOut);
    }else if(e.type === 'mouseleave'){
        clearTimeout(timeOut);
    }


}
